<template><div class="document-page" v-loading="loading"><div class="document-header"><div><el-button link @click="router.push(basePath)"><el-icon><ArrowLeft /></el-icon> 返回列表</el-button><h1>{{ title }}详情</h1><el-tag v-if="detail.status" :type="statusType(detail.status)">{{ statusLabel(detail.status) }}</el-tag></div><div><el-button v-if="detail.status==='DRAFT'" type="success" @click="approve">审核</el-button><el-button v-if="detail.status==='DRAFT'" type="danger" @click="cancel">取消</el-button><el-button v-if="detail.status==='APPROVED'" type="primary" @click="generate">生成退货{{ isSales?'入库':'出库' }}</el-button></div></div><el-card><template #header><b>退货信息</b></template><el-descriptions :column="3" border><el-descriptions-item label="退货单号">{{detail.returnNo}}</el-descriptions-item><el-descriptions-item label="退货日期">{{detail.returnDate}}</el-descriptions-item><el-descriptions-item :label="`原${sourceLabel}`">{{isSales?detail.salesOrderNo:detail.purchaseOrderNo}}</el-descriptions-item><el-descriptions-item :label="partnerLabel">{{isSales?detail.customerName:detail.supplierName}}</el-descriptions-item><el-descriptions-item label="退货仓库">{{detail.warehouseName}}</el-descriptions-item><el-descriptions-item label="退货金额">￥{{money(detail.totalAmount)}}</el-descriptions-item><el-descriptions-item label="退货原因" :span="3">{{detail.returnReason||'-'}}</el-descriptions-item></el-descriptions></el-card><el-card class="detail-card"><template #header><b>退货明细</b></template><el-table :data="detail.items||[]" border><el-table-column prop="productCode" label="商品编码" width="130"/><el-table-column prop="productName" label="商品名称" min-width="180"/><el-table-column prop="specification" label="规格" width="120"/><el-table-column prop="quantity" label="退货数量" width="110"/><el-table-column :prop="isSales?'inboundQuantity':'outboundQuantity'" :label="isSales?'已入库':'已出库'" width="100"/><el-table-column prop="unitPrice" label="单价" width="100"/><el-table-column label="金额" width="120"><template #default="{row}">￥{{money(row.amount)}}</template></el-table-column></el-table></el-card></div></template>
<script setup lang="ts">
import{computed,onMounted,ref}from'vue';import{useRoute,useRouter}from'vue-router';import{ElMessage,ElMessageBox}from'element-plus';import{approveSalesReturn,cancelSalesReturn,getSalesReturn}from'@/api/sales';import{approvePurchaseReturn,cancelPurchaseReturn,getPurchaseReturn}from'@/api/purchase';import{createInboundFromSalesReturn,createOutboundFromPurchaseReturn}from'@/api/inventory';const route=useRoute(),router=useRouter(),loading=ref(false),detail=ref<any>({});const isSales=computed(()=>route.meta.businessType==='sales'),title=computed(()=>isSales.value?'销售退货申请':'采购退货申请'),sourceLabel=computed(()=>isSales.value?'销售单':'采购单'),partnerLabel=computed(()=>isSales.value?'客户':'供应商'),basePath=computed(()=>isSales.value?'/sales/returns':'/purchase/returns');onMounted(load);async function load(){loading.value=true;try{const res=await(isSales.value?getSalesReturn(Number(route.params.id)):getPurchaseReturn(Number(route.params.id)));detail.value=res.data}finally{loading.value=false}}async function approve(){await ElMessageBox.confirm('确认审核这张退货申请？','提示');await(isSales.value?approveSalesReturn(detail.value.id):approvePurchaseReturn(detail.value.id));ElMessage.success('已审核');load()}async function cancel(){await ElMessageBox.confirm('确认取消这张退货申请？','提示');await(isSales.value?cancelSalesReturn(detail.value.id):cancelPurchaseReturn(detail.value.id));ElMessage.success('已取消');load()}async function generate(){await(isSales.value?createInboundFromSalesReturn(detail.value.id):createOutboundFromPurchaseReturn(detail.value.id));ElMessage.success('退货出入库单已生成');load()}function money(v:any){return Number(v||0).toFixed(2)}function statusType(s:string){return({DRAFT:'info',APPROVED:'warning',COMPLETED:'success',CANCELLED:'danger'}as any)[s]||'info'}function statusLabel(s:string){return({DRAFT:'草稿',APPROVED:'已审核',COMPLETED:'已完成',CANCELLED:'已取消'}as any)[s]||s}
</script><style scoped>.document-header{min-height:66px;display:flex;align-items:center;justify-content:space-between;margin:-16px -20px 16px;padding:0 22px;background:#fff;border-bottom:1px solid #edf0f5}.document-header>div{display:flex;align-items:center;gap:12px}.document-header h1{margin:0;font-size:19px}.detail-card{margin-top:14px}</style>
